SELECT A.NMOBILE_IP_SUMMARY_SEQ -- 무선_IP_SUMMARY_SEQ , A.SKIND_CD -- 구분_코드 , A.SKIND_NM -- 구분_명 , A.PIP_PREFIX -- IP 블록 , A.DCREATE_DT , A.SCREATE_ID , A.DMODIFY_DT , A.SMODIFY_ID , A.RNUM FROM ( SELECT A.NMOBILE_IP_SUMMARY_SEQ -- 무선_IP_SUMMARY_SEQ , A.SKIND_CD -- 구분_코드 , A.SKIND_NM -- 구분_명 , A.PIP_PREFIX -- IP 블록 , A.DCREATE_DT , A.SCREATE_ID , A.DMODIFY_DT , A.SMODIFY_ID , ROWNUM RNUM FROM ( SELECT A.NMOBILE_IP_SUMMARY_SEQ -- 무선_IP_SUMMARY_SEQ , A.SKIND_CD -- 구분_코드 , A.SKIND_NM -- 구분_명 , A.PIP_PREFIX -- IP 블록 , A.DCREATE_DT , A.SCREATE_ID , A.DMODIFY_DT , A.SMODIFY_ID FROM MST.TB_MOBILE_IP_SUMMARY_MST A -- 무선IP_Summary_관리 WHERE 1=1
AND A.SKIND_CD = #{skindCd, jdbcType=VARCHAR}
AND (A.PIP_PREFIX >>= (SELECT BIF.UF_SEARCH_IP_TO_ADDRESS(#{pipPrefix, jdbcType=VARCHAR}) AS SIP FROM DUAL) OR A.PIP_PREFIX <<= (SELECT BIF.UF_SEARCH_IP_TO_ADDRESS(#{pipPrefix, jdbcType=VARCHAR}) AS SIP FROM DUAL))
ORDER BY A.NMOBILE_IP_SUMMARY_SEQ ) A WHERE ROWNUM <= #{lastIndex} ) A WHERE RNUM >= #{firstIndex}

SELECT count(1) totalCount FROM MST.TB_MOBILE_IP_SUMMARY_MST A -- 무선IP_Summary_관리 WHERE 1=1
AND A.SKIND_CD = #{skindCd, jdbcType=VARCHAR}
AND (A.PIP_PREFIX >>= (SELECT BIF.UF_SEARCH_IP_TO_ADDRESS(#{pipPrefix, jdbcType=VARCHAR}) AS SIP FROM DUAL) OR A.PIP_PREFIX <<= (SELECT BIF.UF_SEARCH_IP_TO_ADDRESS(#{pipPrefix, jdbcType=VARCHAR}) AS SIP FROM DUAL))

SELECT A.NMOBILE_IP_SUMMARY_SEQ -- 무선_IP_SUMMARY_SEQ , A.SKIND_CD -- 구분_코드 , A.SKIND_NM -- 구분_명 , A.PIP_PREFIX -- IP 블록 , A.DCREATE_DT , A.SCREATE_ID , A.DMODIFY_DT , A.SMODIFY_ID FROM MST.TB_MOBILE_IP_SUMMARY_MST A -- 무선IP_Summary_관리 WHERE 1=1
AND A.SKIND_CD = #{skindCd, jdbcType=VARCHAR}
AND A.PIP_PREFIX = #{pipPrefix, javaType=Object, jdbcType=OTHER, typeHandler=com.kt.ipms.legacy.cmn.typehandler.CIDRTypeHandler}

